// ============================================================================
// VALIDADOR DE TEXTO - Flexível, Multi-item Output + Split por \n\n
// ============================================================================
try {
  const payload = $input.item.json.body || $input.item.json;

  // Validações básicas
  if (!payload.auth?.['dinastia-token']) {
    throw new Error('Campo obrigatório: auth.dinastia-token');
  }

  if (!payload.to) {
    throw new Error('Campo obrigatório: to (telefone)');
  }

  const phoneClean = payload.to.replace(/^\+/, '');
  if (!/^55\d{10,11}$/.test(phoneClean)) {
    throw new Error(`Telefone inválido: ${payload.to}. Formato: 5511999999999`);
  }

  // ========================================================================
  // NORMALIZAÇÃO INTELIGENTE: detecta qualquer variação
  // ========================================================================
  let messagesToProcess = [];

  // Tentar encontrar mensagens em qualquer formato
  const possibleKeys = ['message', 'messages', 'Message', 'Messages'];
  let foundMessages = null;

  for (const key of possibleKeys) {
    if (payload[key]) {
      foundMessages = payload[key];
      break;
    }
  }

  if (!foundMessages) {
    throw new Error('Deve informar "message" (única) ou "messages" (array)');
  }

  // Normalizar para array
  if (Array.isArray(foundMessages)) {
    // Já é array
    if (foundMessages.length === 0) {
      throw new Error('Array de mensagens não pode estar vazio');
    }
    messagesToProcess = foundMessages;
  } else if (typeof foundMessages === 'object') {
    // É um objeto único - transformar em array
    messagesToProcess = [foundMessages];
  } else {
    throw new Error('Formato de mensagem inválido');
  }

  // ========================================================================
  // VALIDAR, PROCESSAR e QUEBRAR cada mensagem por \n\n
  // ========================================================================
  const validatedMessages = [];

  messagesToProcess.forEach((msg, index) => {
    const msgNum = index + 1;

    // Validar tipo (se informado)
    if (msg.type && msg.type !== 'text') {
      throw new Error(`Mensagem ${msgNum}: tipo deve ser "text", recebido "${msg.type}"`);
    }

    // Validar texto
    if (!msg.text) {
      throw new Error(`Mensagem ${msgNum}: campo "text" é obrigatório`);
    }

    // Aceitar text como string ou objeto {body: "..."}
    let textContent = typeof msg.text === 'string' 
      ? msg.text 
      : msg.text?.body;

    if (!textContent || textContent.trim().length === 0) {
      throw new Error(`Mensagem ${msgNum}: text não pode estar vazio`);
    }

    // ========================================================================
    // QUEBRAR por \n\n (dupla quebra de linha)
    // ========================================================================
    const splitMessages = textContent
      .split(/\n\n+/)  // Split por 2 ou mais \n consecutivos
      .map(part => part.trim())
      .filter(part => part.length > 0);  // Remove vazios

    // Se não houver quebras, retorna a mensagem inteira
    if (splitMessages.length === 0) {
      validatedMessages.push({
        type: 'text',
        text: textContent.trim()
      });
    } else {
      // Adiciona cada parte como mensagem separada
      splitMessages.forEach(part => {
        validatedMessages.push({
          type: 'text',
          text: part
        });
      });
    }
  });

  // ========================================================================
  // OUTPUT: Criar um item para cada mensagem (agora expandido)
  // ========================================================================
  return validatedMessages.map((msg, index) => ({
    json: {
      auth: {
        'dinastia-token': payload.auth['dinastia-token']
      },
      to: phoneClean,
      message: msg,
      message_index: index + 1,
      total_messages: validatedMessages.length,
      ...(payload.meta && { meta: payload.meta }),
      ...(payload.config && { config: payload.config }),
      ...(payload.context && { context: payload.context })
    }
  }));

} catch (error) {
  throw new Error(`❌ Erro no contrato: ${error.message}`);
}

