// ============================================================================

try {
  const allItems = $input.all();

  let totalSent = 0;
  let totalFailed = 0;

  const messagesResults = allItems.map((item, index) => {
    try {
      const data = item.json;

      // Verificar se foi sucesso (múltiplas formas)
      const isSuccess = data.success === true || 
                        data.code === 200 || 
                        data.data?.Details === "Sent" ||
                        data.Details === "Sent" ||
                        data.status === "success";

      if (isSuccess) {
        totalSent++;
        return {
          index: index,
          status: "sent",
          provider_message_id: data.data?.Id || data.Id || data.messageId || null,
          timestamp: data.data?.Timestamp || data.Timestamp || new Date().toISOString()
        };
      } else {
        totalFailed++;
        return {
          index: index,
          status: "failed",
          error: {
            code: data.error?.code || 
                  data.data?.error_code || 
                  data.code || 
                  "UNKNOWN_ERROR",
            message: data.error?.message || 
                     data.data?.error || 
                     data.message || 
                     "Erro desconhecido ao enviar mensagem"
          },
          raw_response: data // Replica resposta original
        };
      }

    } catch (itemError) {
      // Se der erro ao processar um item específico
      totalFailed++;
      return {
        index: index,
        status: "failed",
        error: {
          code: "PROCESSING_ERROR",
          message: `Erro ao processar item: ${itemError.message}`
        },
        raw_response: item.json // Replica payload original
      };
    }
  });

  // Montar resposta consolidada
  const consolidatedResponse = {
    success: totalFailed === 0,
    summary: {
      total: allItems.length,
      sent: totalSent,
      failed: totalFailed
    },
    messages: messagesResults
  };

  return [{ json: consolidatedResponse }];

} catch (error) {
  // Se der erro geral na agregação
  return [{
    json: {
      success: false,
      summary: {
        total: 0,
        sent: 0,
        failed: 0
      },
      messages: [],
      error: {
        code: "AGGREGATION_ERROR",
        message: error.message
      },
      raw_error: error.stack
    }
  }];
